VALUES
  ('social-worker-moex-00761', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在助人改變行為上，行為理論是很實用的理論。下列敘述何者錯誤？', '["系統減敏感法背後的原理是反應制約", "操作制約是針對可以觀察的行為來做改變", "角色扮演即是一種模仿，透過觀察和模仿楷模而習得行為", "移除負面事件會增加某個行為的頻率，這是懲罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00762', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Duvall（1977）將家庭生命週期分為八個階段，其中第七個階段為中年期的家庭（夫妻進入空巢 期與退休），下列何者不是此階段任務？', '["婚姻關係的重新調適", "調整及適應父母與成年子女的代間關係", "適當協助年輕人就業、就學與婚姻", "增強自己參與社區及休閒活動的能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00763', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於家庭界限的敘述，下列何者錯誤？', '["喪偶者因懷念配偶，會在用餐時準備另一份碗筷，這是高度的界限模糊", "家庭成員較孤立，彼此漠不關心或甚少接觸，這樣的家庭界限是鬆散的", "家庭中次系統界限是否分明可以用來評估家庭的功能狀況", "家庭界限是浮動的、非固定不變的，通常會隨著家庭的發展歷程而改變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00764', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作者服務的案家時常面臨家庭壓力事件，若依據家庭壓力理論的觀點，下列何者不是社會 工作者關注的事項？', '["了解案家既有資源並連結新的資源", "協助案家倡議因應壓力事件的社會政策", "鼓勵案家修復家庭關係以因應壓力事件", "協助案家辨識出壓力事件的來源"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00765', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '涂爾幹（Durkheim）主張社會變遷過快導致人們喪失生活意義和目的感，連帶地也無法控制個人 行為，此過程指的是下列何者？', '["社會分工（thedivisionoflabor）", "有機連帶（organicsolidarity）", "社會連帶（socialsolidarity）", "迷亂（anomie）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00766', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '擁有社會資源者為長期確保其既得權益，透過教育的方式強迫沒有資源者內化現有不平等安排的 合理性。此為下列何種觀點？', '["功能論", "衝突論", "符號互動論", "交換論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00767', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關中年人更年期的敘述，下列組合何者正確？①更年期的賀爾蒙流失、心理及情緒變化，常被', '["兩性的骨質疏鬆在年齡上是相同的", "中年人過了 40 歲，體力大不如前", "中年期除了體重與生理變化外，最先凸顯的是視力，需要戴老花眼鏡，其次頭髮開始斑白，嗅 覺、味覺等也較不敏感", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00768', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關生態理論的敘述，下列何者錯誤？', '["人類的發展係藉由個人、環境及個人與環境雙方交互作用而來的結果", "人類的發展是被動因應外在環境刺激及變化所產生逐步演化的結果", "人們生來就有消極和積極的傾向，它受先天自然和後天養成的影響", "人們感知其環境與經驗的方式，對自身福祉的取得有著重要的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00769', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '兒童跟主要照顧者分離後，常會害怕將有不幸的事發生在自己或家人身上，因此他們會用盡各種 方法避免分離。這類焦慮屬於下列何者？', '["分離焦慮症（separationanxietydisorder）", "迴避性障礙（avoidantdisorder）", "廣泛性焦慮症（generalizedanxietydisorder）", "過度焦慮症（overanxiousdisorder）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00770', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '4 歲的小莉擋住姊姊看電視，因為自己看得到，就認為姊姊也看得到，這種認知推理屬於下列何 者？', '["轉換式推理", "自我中心", "反射性思考", "直覺式思考"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
